const createTraderOutboundUnpaidPayoutItems = `-- name: CreateTraderOutboundUnpaidPayoutItems :exec
WITH payout_totals AS (
    SELECT
        mpo.id,
        mpo.destination_bank,
        mpo.destination_requisite,
        mpo.amount_minor,
        COALESCE(sum(mpt.amount_minor), 0)::bigint AS paid_amount_minor
    FROM manual_payout_orders mpo
    LEFT JOIN manual_payout_transfers mpt ON mpt.manual_payout_order_id = mpo.id
    WHERE mpo.team_id = $2
      AND mpo.trader_id = $3
      AND mpo.shift_id = $4
      AND mpo.deleted_at IS NULL
      AND mpo.status <> 'cancelled'
    GROUP BY mpo.id
)
INSERT INTO reconciliation_items (
    reconciliation_run_id,
    issue_type,
    trader_value_json,
    message
)
SELECT
    $1,
    'payout_not_fully_paid',
    jsonb_build_object(
        'manualPayoutOrderId', id,
        'destinationBank', destination_bank,
        'destinationRequisite', destination_requisite,
        'amountMinor', amount_minor,
        'paidAmountMinor', paid_amount_minor,
        'remainingAmountMinor', amount_minor - paid_amount_minor
    ),
    'Manual payout order is not fully paid'
FROM payout_totals
WHERE paid_amount_minor <> amount_minor
`

type CreateTraderOutboundUnpaidPayoutItemsParams struct {
	RunID    int64
	TeamID   int64
	TraderID int64
	ShiftID  int64
}

func (q *Queries) CreateTraderOutboundUnpaidPayoutItems(ctx context.Context, arg CreateTraderOutboundUnpaidPayoutItemsParams) error {
	_, err := q.db.Exec(ctx, createTraderOutboundUnpaidPayoutItems,
		arg.RunID,
		arg.TeamID,
		arg.TraderID,
		arg.ShiftID,
	)
	return err
}

