const listActiveTeamleadInboundPeriodScopes = `-- name: ListActiveTeamleadInboundPeriodScopes :many
SELECT DISTINCT ON (ib.accounting_period_id)
    ib.accounting_period_id,
    ib.id AS import_batch_id
FROM import_batches ib
WHERE ib.team_id = $1
  AND ib.scope_type = 'teamlead_period'
  AND ib.direction = 'inbound'
  AND ib.status IN ('applied', 'reconciled')
  AND ib.accounting_period_id IS NOT NULL
  AND ib.superseded_by_batch_id IS NULL
ORDER BY ib.accounting_period_id, ib.applied_at DESC NULLS LAST, ib.id DESC
`

type ListActiveTeamleadInboundPeriodScopesRow struct {
	AccountingPeriodID pgtype.Int8
	ImportBatchID      int64
}

func (q *Queries) ListActiveTeamleadInboundPeriodScopes(ctx context.Context, teamID int64) ([]ListActiveTeamleadInboundPeriodScopesRow, error) {
	rows, err := q.db.Query(ctx, listActiveTeamleadInboundPeriodScopes, teamID)
	if err != nil {
		return nil, err
	}
	defer rows.Close()
	var items []ListActiveTeamleadInboundPeriodScopesRow
	for rows.Next() {
		var i ListActiveTeamleadInboundPeriodScopesRow
		if err := rows.Scan(&i.AccountingPeriodID, &i.ImportBatchID); err != nil {
			return nil, err
		}
		items = append(items, i)
	}
	if err := rows.Err(); err != nil {
		return nil, err
	}
	return items, nil
}

